              </div>
            </div>

            <button
              onClick={handleReset}
              className="px-6 py-3 bg-gray-200 hover:bg-gray-300 dark:bg-gray-800 dark:hover:bg-gray-700 text-gray-900 dark:text-white rounded-xl font-medium transition-colors w-full"
            >
              Pay Another Bill
            </button>
          </div>
        </motion.div>
      )}
    </div>
  );
}

